// Витягуємо ID голосового файлу з повідомлення Telegram
const msg = $('Telegram Trigger').item.json.message;
const fileId = msg && msg.voice ? msg.voice.file_id : null;
return { json: { voice_file_id: fileId } };

const msg = $('Telegram Trigger').item.json.message;
const fileId = msg && msg.document ? msg.document.file_id : null;
const fileName = msg && msg.document ? msg.document.file_name : 'document.pdf';
return { json: { pdf_file_id: fileId, file_name: fileName } };

// ---- Unified handler for all branches (Text / Voice / PDF / Photo) ----
// Live currency rates come from the Get Rates node (this node's direct input).
const rates = ($input.item.json.rates) || {};
const rateUah = Number(rates.UAH) || 0.55;      // UAH per 1 ALL (fallback)
const rateEur = Number(rates.EUR) || (1 / 94);  // EUR per 1 ALL (fallback)

// Detect source type from the original Telegram message
const msg = ($('Telegram Trigger').item.json.message) || {};
let sourceType = 'Text / Google Pay';
if (msg.voice) sourceType = 'Voice';
else if (msg.document) sourceType = 'Чек (PDF)';
else if (msg.photo) sourceType = 'Фото-чек';

// Raw AI text comes from the merged Gemini output
const inp = ($('Merge Branches').item.json) || {};
let rawText = '';
if (inp.candidates && inp.candidates[0] && inp.candidates[0].content && inp.candidates[0].content.parts && inp.candidates[0].content.parts[0] && typeof inp.candidates[0].content.parts[0].text === 'string') {
  rawText = inp.candidates[0].content.parts[0].text;
} else if (typeof inp.text === 'string') {
  rawText = inp.text;
} else if (typeof inp.content === 'string') {
  rawText = inp.content;
} else {
  rawText = JSON.stringify(inp);
}
rawText = String(rawText).replace(/```json/gi, '').replace(/```/g, '').trim();

// Parse JSON (with bracket-slice fallback)
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  const s = rawText.indexOf('[');
  const en = rawText.lastIndexOf(']');
  if (s !== -1 && en !== -1 && en > s) {
    parsed = JSON.parse(rawText.substring(s, en + 1));
  } else {
    throw new Error('Не вдалося розпарсити JSON від ШІ. Сирий текст: ' + rawText);
  }
}

// Normalise to array with flexible key fallbacks
let arr = Array.isArray(parsed)
  ? parsed
  : (parsed.items || parsed.products || parsed.goods || parsed['товары'] || parsed['покупки'] || [parsed]);
if (!Array.isArray(arr) || arr.length === 0) {
  throw new Error('Масив товарів порожній! Структура: ' + JSON.stringify(parsed));
}

const nowStr = $now.format('dd-MM-yyyy HH:mm');

return arr.map(it => {
  const name = it.product_name || it.product || it.name || it['товар'] || 'Невідомий товар';
  const qty = parseFloat(it.quantity) || parseFloat(it.amount) || parseFloat(it['кількість']) || 1;
  const price = parseFloat(it.price_per_unit) || parseFloat(it.price) || parseFloat(it.unit_price) || 0;
  const totalLek = parseFloat(it.total_lek) || parseFloat(it.total) || parseFloat(it.total_all) || (qty * price);
  return {
    json: {
      date: nowStr,
      source_type: sourceType,
      product_name: name,
      quantity: qty,
      price_per_unit: price,
      total_lek: totalLek,
      total_uah: parseFloat((totalLek * rateUah).toFixed(2)),
      total_eur: parseFloat((totalLek * rateEur).toFixed(2)),
    },
  };
});

